/**
 * @fileoverview Heading view setup.
 * @module module/Heading/view
 */

import { PART, LEVEL_STYLES } from './constants.js';

export function setupDOM(root) {
    PART.ROOT.apply(root);

    // Auto-detect heading level and apply size/weight tokens
    const el = root[0];
    const tag = el.tagName?.toLowerCase();
    const level = LEVEL_STYLES[tag];
    if (level) {
        if (!el.style.getPropertyValue('--hd-size'))   el.style.setProperty('--hd-size', level.size);
        if (!el.style.getPropertyValue('--hd-weight')) el.style.setProperty('--hd-weight', level.weight);
    }

    return {};
}
