/**
 * @fileoverview Heading barrel.
 * @module module/Heading
 */
import { default as razyui } from '../index.js';
import { HeadingDef as DEF } from './Heading.def.js';
import Heading from './Heading/index.js';

razyui.Heading = Heading;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Heading);
}

export default Heading;

export const stylesheet = null;
